                this.addSemanticDiagnostic(com.omnifret.gplayer.importer.gplayertex.GPlayerTexDiagnostic(code = com.omnifret.gplayer.importer.gplayertex.GPlayerTexDiagnosticCode.AT218, message = """Wrong note kind '${(detectedNoteKind!!.toString()).toTemplate()}' for staff with note kind ''${(staffNoteKind!!.toString()).toTemplate()}'. Do not mix incompatible staves and notes.""", severity = com.omnifret.gplayer.importer.gplayertex.GPlayerTexDiagnosticsSeverity.Error, start = noteValue.start, end = noteValue.end))
            }
        }
        else if (staffNoteKind != null)
        {
            detectedNoteKind = staffNoteKind!!
        }
        var note: com.omnifret.gplayer.model.Note = com.omnifret.gplayer.model.Note()
        note.isDead = isDead
        if (isDead || isTie)
        {
            note.fret = numericValue
        }
        note.isTieDestination = isTie
        if (detectedNoteKind != null && detectedNoteKind!! == staffNoteKind)
        {
            when (detectedNoteKind!!)
            {
                com.omnifret.gplayer.importer.gplayertex.GPlayerTexStaffNoteKind.Pitched -> 
                {
                    note.octave = octave
                    note.tone = tone
                    note.accidentalMode = accidentalMode
                }
                com.omnifret.gplayer.importer.gplayertex.GPlayerTexStaffNoteKind.Fretted -> 
                {
                    if (!com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(node.noteString)))
                    {
                        this.addSemanticDiagnostic(com.omnifret.gplayer.importer.gplayertex.GPlayerTexDiagnostic(code = com.omnifret.gplayer.importer.gplayertex.GPlayerTexDiagnosticCode.AT207, message = "Missing string for fretted note.", severity = com.omnifret.gplayer.importer.gplayertex.GPlayerTexDiagnosticsSeverity.Error, start = noteValue.end, end = noteValue.end))
                        return
                    }
                    var noteString: Double = node.noteString!!.value
                    if (noteString < 1 || noteString > this._state.currentStaff!!.tuning.length)
                    {
                        this.addSemanticDiagnostic(com.omnifret.gplayer.importer.gplayertex.GPlayerTexDiagnostic(code = com.omnifret.gplayer.importer.gplayertex.GPlayerTexDiagnosticCode.AT208, message = """Note string is out of range. Available range: 1-${(this._state.currentStaff!!.tuning.length).toTemplate()}""", severity = com.omnifret.gplayer.importer.gplayertex.GPlayerTexDiagnosticsSeverity.Error, start = noteValue.end, end = noteValue.end))
                        return
                    }
                    note.string = this._state.currentStaff!!.tuning.length - (noteString - (1.0).toDouble())
                    if (!isTie)
                    {
                        note.fret = numericValue
                    }
                }
                com.omnifret.gplayer.importer.gplayertex.GPlayerTexStaffNoteKind.Articulation -> 
                {
                    var articulationIndex: Double = 0.0
                    if (articulationValue.length.toDouble() == 0.0 && numericValue > 0)
                    {
                        var byId: com.omnifret.gplayer.model.InstrumentArticulation? = com.omnifret.gplayer.model.PercussionMapper.getArticulationById(numericValue)
                        if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(byId)))
                        {
                            articulationValue = byId!!.uniqueId
                        }
                    }
                    if (this._state.articulationUniqueIdToIndex.has(articulationValue))
                    {
                        articulationIndex = this._state.articulationUniqueIdToIndex.get(articulationValue)!!
                    }
                    else 
                    {
                        articulationIndex = this._state.currentTrack!!.percussionArticulations.length
                        var articulation: com.omnifret.gplayer.model.InstrumentArticulation? = com.omnifret.gplayer.model.PercussionMapper.getInstrumentArticulationByUniqueId(articulationValue)
                        if (articulation == null)
                        {
                            this.addSemanticDiagnostic(com.omnifret.gplayer.importer.gplayertex.GPlayerTexDiagnostic(code = com.omnifret.gplayer.importer.gplayertex.GPlayerTexDiagnosticCode.AT209, message = """Unexpected articulation value '${(numericValue).toTemplate()}', expected: oneOf(${(com.omnifret.gplayer.core.ecmaScript.Array.from(com.omnifret.gplayer.model.PercussionMapper.instrumentArticulations.keys()).join(",")).toTemplate()}).""", severity = com.omnifret.gplayer.importer.gplayertex.GPlayerTexDiagnosticsSeverity.Error, start = noteValue.end, end = noteValue.end))
                            return
                        }
                        this._state.currentTrack!!.percussionArticulations.push(articulation!!)
                        this._state.articulationUniqueIdToIndex.set(articulationValue, articulationIndex)
                    }
                    note.percussionArticulation = articulationIndex
                }
                else -> { }
            }
        }
        beat.addNote(note)
        this._state.hasAnyProperData = true
        if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(node.noteEffects)))
        {
            this._noteEffects(note, node.noteEffects!!)
        }
    }
    
    /**
     */
    internal fun getStaffNoteKind(staff: com.omnifret.gplayer.model.Staff): com.omnifret.gplayer.importer.gplayertex.GPlayerTexStaffNoteKind?{
        return if(this._state.staffNoteKind.has(staff))  this._state.staffNoteKind.get(staff) else null
    }
    
    /**
     */
    public override fun applyStaffNoteKind(staff: com.omnifret.gplayer.model.Staff, staffNoteKind: com.omnifret.gplayer.importer.gplayertex.GPlayerTexStaffNoteKind): Unit{
        this._state.staffNoteKind.set(staff, staffNoteKind)
        when (staffNoteKind)
        {
            com.omnifret.gplayer.importer.gplayertex.GPlayerTexStaffNoteKind.Pitched -> 
            {
                staff.isPercussion = false
                staff.stringTuning.reset()
                if (!this._state.staffHasExplicitDisplayTransposition.has(staff))
                {
                    staff.displayTranspositionPitch = 0.0
                }
            }
            com.omnifret.gplayer.importer.gplayertex.GPlayerTexStaffNoteKind.Fretted -> 
            {
                staff.isPercussion = false
                this._detectTuningForStaff(staff)
                this._handleTransposition(staff)
            }
            com.omnifret.gplayer.importer.gplayertex.GPlayerTexStaffNoteKind.Articulation -> 
            {
                staff.isPercussion = true
                staff.stringTuning.reset()
                if (!this._state.staffHasExplicitDisplayTransposition.has(staff))
                {
                    staff.displayTranspositionPitch = 0.0
                }
            }
            else -> { }
        }
    }
    
    /**
     */
    private fun _noteEffects(note: com.omnifret.gplayer.model.Note, node: com.omnifret.gplayer.importer.gplayertex.GPlayerTexPropertiesNode): Unit{
        for (p in node.properties)
        {
            var result: com.omnifret.gplayer.importer.gplayertex.ApplyNodeResult = this._handler.applyNoteProperty(this, note, p)
            if (result == com.omnifret.gplayer.importer.gplayertex.ApplyNodeResult.NotAppliedUnrecognizedMarker)
            {
                result = this._handler.applyBeatProperty(this, note.beat, p)
            }
            when (result)
            {
                com.omnifret.gplayer.importer.gplayertex.ApplyNodeResult.Applied, com.omnifret.gplayer.importer.gplayertex.ApplyNodeResult.NotAppliedSemanticError -> 
                {
                }
                com.omnifret.gplayer.importer.gplayertex.ApplyNodeResult.NotAppliedUnrecognizedMarker -> 
                {
                    var knownProps: String = com.omnifret.gplayer.core.ecmaScript.Array.from(this._handler.knownNoteProperties).concat(com.omnifret.gplayer.core.ecmaScript.Array.from(this._handler.knownBeatProperties)).join(",")
                    this.addSemanticDiagnostic(com.omnifret.gplayer.importer.gplayertex.GPlayerTexDiagnostic(code = com.omnifret.gplayer.importer.gplayertex.GPlayerTexDiagnosticCode.AT212, message = """Unrecogized property '${(p.property.text).toTemplate()}', expected one of ${(knownProps).toTemplate()}""", severity = com.omnifret.gplayer.importer.gplayertex.GPlayerTexDiagnosticsSeverity.Error, start = p.start, end = p.end))
                }
                else -> { }
            }
        }
    }
    
    /**
     */
    private fun _handleTransposition(staff: com.omnifret.gplayer.model.Staff): Unit{
        if (!this._state.staffDisplayTranspositionApplied.has(staff) && !this._state.staffHasExplicitDisplayTransposition.has(staff))
        {
            var program: Double = staff.track.playbackInfo.program
            if (com.omnifret.gplayer.model.ModelUtils.displayTranspositionPitches.has(program))
            {
                staff.displayTranspositionPitch = com.omnifret.gplayer.model.ModelUtils.displayTranspositionPitches.get(program)!!
            }
            else 
            {
                this._state.currentStaff!!.displayTranspositionPitch = 0.0
            }
            this._state.staffDisplayTranspositionApplied.add(staff)
        }
    }
    
    /**
     */
    private fun _detectTuningForStaff(staff: com.omnifret.gplayer.model.Staff): Unit{
        var program: Double = staff.track.playbackInfo.program
        if (!this._state.staffTuningApplied.has(staff) && !this._state.staffHasExplicitTuning.has(staff))
        {
            staff.stringTuning.reset()
            if (program == 15.0)
            {
                staff.stringTuning.tunings = com.omnifret.gplayer.model.Tuning.getDefaultTuningFor(6.0)!!.tunings
            }
            else if (program >= 24 && program <= 31)
            {
                staff.stringTuning.tunings = com.omnifret.gplayer.model.Tuning.getDefaultTuningFor(6.0)!!.tunings
            }
            else if (program >= 32 && program <= 39)
            {
                staff.stringTuning.tunings = com.omnifret.gplayer.collections.DoubleList(
                    43.0, 38.0, 33.0, 28.0)
                
                this._state.staffInitialClef.set(staff, com.omnifret.gplayer.model.Clef.F4)
            }
            else if (program == 40.0 || program == 44.0 || program == 45.0 || program == 48.0 || program == 49.0 || program == 50.0 || program == 51.0)
            {
                staff.stringTuning.tunings = com.omnifret.gplayer.collections.DoubleList(
                    52.0, 57.0, 50.0, 43.0)
                
            }
            else if (program == 41.0)
            {
                staff.stringTuning.tunings = com.omnifret.gplayer.collections.DoubleList(
                    57.0, 50.0, 43.0, 36.0)
                
            }
            else if (program == 42.0)
            {
                staff.stringTuning.tunings = com.omnifret.gplayer.collections.DoubleList(
                    45.0, 38.0, 31.0, 24.0)
                
            }
            else if (program == 43.0)
            {
                staff.stringTuning.tunings = com.omnifret.gplayer.collections.DoubleList(
                    43.0, 38.0, 33.0, 28.0)
                
            }
            else if (program == 105.0)
            {
                staff.stringTuning.tunings = com.omnifret.gplayer.collections.DoubleList(
                    50.0, 47.0, 43.0, 38.0, 55.0)
                
            }
            else if (program == 106.0)
            {
                staff.stringTuning.tunings = com.omnifret.gplayer.collections.DoubleList(
                    57.0, 52.0, 45.0)
                
            }
            else if (program == 107.0)
            {
                staff.stringTuning.tunings = com.omnifret.gplayer.collections.DoubleList(
                    52.0, 45.0, 38.0, 31.0)
                
            }
            else if (program == 110.0)
            {
                staff.stringTuning.tunings = com.omnifret.gplayer.collections.DoubleList(
                    64.0, 57.0, 50.0, 43.0)
                
            }
            else 
            {
                if (this._state.staffNoteKind.has(staff) && this._state.staffNoteKind.get(staff)!! == com.omnifret.gplayer.importer.gplayertex.GPlayerTexStaffNoteKind.Fretted)
                {
                    staff.stringTuning = com.omnifret.gplayer.model.Tuning.getDefaultTuningFor(6.0)!!
                }
            }
            this._state.staffTuningApplied.add(staff)
        }
    }
    
    /**
     */
    private fun _barMeta(node: com.omnifret.gplayer.importer.gplayertex.GPlayerTexBarNode, previousBarCompleted: Boolean): com.omnifret.gplayer.model.Bar{
        var initialBarMeta: com.omnifret.gplayer.collections.List<com.omnifret.gplayer.importer.gplayertex.GPlayerTexMetaDataNode>? = if(this._state.score.masterBars.length > 0)  null else com.omnifret.gplayer.collections.List<com.omnifret.gplayer.importer.gplayertex.GPlayerTexMetaDataNode>(
        )
        
        var previousStaff: com.omnifret.gplayer.model.Staff = this._state.currentStaff!!
        var hadNewTrack: Boolean = false
        var hadNewStaff: Boolean = false
        var hadNewVoice: Boolean = false
        var applyInitialBarMetaToPreviousStaff: Boolean = false
        var resetInitialBarMeta: (() -> Unit) = fun(): Unit{
            if (!com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(initialBarMeta)))
            {
                return
            }
            initialBarMeta = null
            previousStaff = this._state.currentStaff!!
            hadNewTrack = false
            hadNewStaff = false
            hadNewVoice = false
            applyInitialBarMetaToPreviousStaff = false
        }
        
        var bar: com.omnifret.gplayer.util.Lazy<com.omnifret.gplayer.model.Bar> = com.omnifret.gplayer.util.Lazy<com.omnifret.gplayer.model.Bar>(fun(): com.omnifret.gplayer.model.Bar{
            if (!hadNewVoice && !previousBarCompleted)
            {
                this._state.barIndex++
            }
            var b: com.omnifret.gplayer.model.Bar = this._getBar(this._state.currentStaff!!)
            if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(initialBarMeta)))
            {
                for (initial in initialBarMeta!!)
                {
                    this._handler.applyBarMetaData(this, b, initial)
                }
                resetInitialBarMeta()
            }
            return b
        }
        )
        for (m in node.metaData)
        {
            var tag: String = m.tag.tag.text.lowercase()
            if (this._handler.knownStructuralMetaDataTags.has(tag))
            {
                this._state.hasAnyProperData = true
                var result: com.omnifret.gplayer.importer.gplayertex.ApplyStructuralMetaDataResult = this._handler.applyStructuralMetaData(this, m)
                when (result)
                {
                    com.omnifret.gplayer.importer.gplayertex.ApplyStructuralMetaDataResult.AppliedNewTrack -> 
                    {
                        if (hadNewStaff)
                        {
                            applyInitialBarMetaToPreviousStaff = true
                        }
                        else if (hadNewTrack)
                        {
                            applyInitialBarMetaToPreviousStaff = true
                        }
                        else 
                        {
                            hadNewTrack = true
                            previousStaff = this._state.currentStaff!!
                        }
                        bar.reset()
                    }
                    com.omnifret.gplayer.importer.gplayertex.ApplyStructuralMetaDataResult.AppliedNewStaff -> 
                    {
                        if (hadNewStaff)
                        {
                            applyInitialBarMetaToPreviousStaff = true
                        }
                        else 
                        {
                            hadNewStaff = true
                            previousStaff = this._state.currentStaff!!
                        }
                        bar.reset()
                    }
                    com.omnifret.gplayer.importer.gplayertex.ApplyStructuralMetaDataResult.AppliedNewVoice -> 
                    {
                        hadNewVoice = true
                    }
                    else -> { }
                }
                if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(initialBarMeta)))
                {
                    if (applyInitialBarMetaToPreviousStaff)
                    {
                        if (previousStaff.bars.length == 0.0)
                        {
                            var initialBar: com.omnifret.gplayer.model.Bar = com.omnifret.gplayer.model.Bar()
                            previousStaff.addBar(initialBar)
                            var initialVoice: com.omnifret.gplayer.model.Voice = com.omnifret.gplayer.model.Voice()
                            initialBar.addVoice(initialVoice)
                            if (previousStaff.bars.length > this._state.score.masterBars.length)
                            {
                                var master: com.omnifret.gplayer.model.MasterBar = com.omnifret.gplayer.model.MasterBar()
                                this._state.score.addMasterBar(master)
                            }
                            for (initial in initialBarMeta!!)
                            {
                                this._handler.applyBarMetaData(this, initialBar, initial)
                            }
                            resetInitialBarMeta()
                        }
                        else 
                        {
                            throw com.omnifret.gplayer.GPlayerError(com.omnifret.gplayer.GPlayerErrorType.GPlayerTex, "Unexpected internal error, didn't expect a filled staff after multiple \\track and/or \\staff tags. Please report this problem providing the input gplayertex.")
                        }
                    }
                }
            }
            else if (this._handler.knownScoreMetaDataTags.has(m.tag.tag.text.lowercase()))
            {
                this._state.hasAnyProperData = true
                this._handler.applyScoreMetaData(this, this._state.score, m)
            }
            else if (this._handler.knownStaffMetaDataTags.has(m.tag.tag.text.lowercase()))
            {
                this._state.hasAnyProperData = true
                this._handler.applyStaffMetaData(this, this._state.currentStaff!!, m)
            }
            else if (this._handler.knownBarMetaDataTags.has(m.tag.tag.text.lowercase()))
            {
                this._state.hasAnyProperData = true
                if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(initialBarMeta)))
                {
                    initialBarMeta!!.push(m)
                }
                else 
                {
                    this._handler.applyBarMetaData(this, bar.value, m)
                }
            }
            else 
            {
                var knownMeta: String = com.omnifret.gplayer.core.ecmaScript.Array.from(this._handler.allKnownMetaDataTags).join(",")
                this.addSemanticDiagnostic(com.omnifret.gplayer.importer.gplayertex.GPlayerTexDiagnostic(code = com.omnifret.gplayer.importer.gplayertex.GPlayerTexDiagnosticCode.AT204, message = """Unrecognized metadata '${(m.tag.tag.text).toTemplate()}', expected one of: ${(knownMeta).toTemplate()}""", severity = com.omnifret.gplayer.importer.gplayertex.GPlayerTexDiagnosticsSeverity.Error, start = m.tag.start, end = m.tag.end))
            }
        }
        return bar.value
    }
    
    /**
     */
    private fun _getBar(staff: com.omnifret.gplayer.model.Staff): com.omnifret.gplayer.model.Bar{
        if (this._state.barIndex < staff.bars.length)
        {
            var bar: com.omnifret.gplayer.model.Bar = staff.bars[(this._state.barIndex).toInt()]
            return bar
        }
        var voiceCount: Double = if(staff.bars.length == 0.0)  this._state.voiceIndex + 1.0 else staff.bars[(0).toInt()].voices.length
        var newBar: com.omnifret.gplayer.model.Bar = com.omnifret.gplayer.model.Bar()
        staff.addBar(newBar)
        if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(newBar.previousBar)))
        {
            newBar.clef = newBar.previousBar!!.clef
            newBar.clefOttava = newBar.previousBar!!.clefOttava
            newBar.keySignature = newBar.previousBar!!.keySignature
            newBar.keySignatureType = newBar.previousBar!!.keySignatureType
        }
        this._state.barIndex = newBar.index
        if (newBar.index > 0)
        {
            newBar.clef = newBar.previousBar!!.clef
        }
        if (true) {
            var i: Double = 0.0
            
            while(i < voiceCount){
                var voice: com.omnifret.gplayer.model.Voice = com.omnifret.gplayer.model.Voice()
                newBar.addVoice(voice)
                i++
            }
        }
        if (this._state.currentStaff!!.bars.length > this._state.score.masterBars.length)
        {
            var master: com.omnifret.gplayer.model.MasterBar = com.omnifret.gplayer.model.MasterBar()
            this._state.score.addMasterBar(master)
            if (master.index > 0)
            {
                master.timeSignatureDenominator = master.previousMasterBar!!.timeSignatureDenominator
                master.timeSignatureNumerator = master.previousMasterBar!!.timeSignatureNumerator
                master.tripletFeel = master.previousMasterBar!!.tripletFeel
            }
        }
        return newBar
    }
    
    public override fun startNewStaff(): com.omnifret.gplayer.model.Staff{
        this._state.ignoredInitialVoice = false
        if (this._state.ignoredInitialStaff || this._state.currentTrack!!.staves[(0).toInt()].bars.length > 0)
        {
            var previousWasPercussion: Boolean = this._state.currentStaff!!.isPercussion
            this._state.currentTrack!!.ensureStaveCount(this._state.currentTrack!!.staves.length + 1.0)
            var staff: com.omnifret.gplayer.model.Staff = this._state.currentTrack!!.staves[(this._state.currentTrack!!.staves.length - (1.0).toDouble()).toInt()]
            this._beginStaff(staff)
            if (previousWasPercussion)
            {
                this.applyPercussionStaff(this._state.currentStaff!!)
            }
            this._state.currentDynamics = com.omnifret.gplayer.model.DynamicValue.F
        }
        else 
        {
            this._state.ignoredInitialStaff = true
        }
        return this._state.currentStaff!!
    }
    
    /**
     */
    public fun applyPercussionStaff(staff: com.omnifret.gplayer.model.Staff): Unit{
        staff.isPercussion = true
        staff.showTablature = false
        staff.track.playbackInfo.program = 0.0
    }
    
    public override fun startNewTrack(): com.omnifret.gplayer.model.Track{
        this._state.ignoredInitialVoice = false
        this._state.ignoredInitialStaff = false
        if (this._state.ignoredInitialTrack || this._state.score.masterBars.length > 0)
        {
            this._newTrack()
        }
        else 
        {
            this._state.ignoredInitialTrack = true
        }
        return this._state.currentTrack!!
    }
    
    public override fun startNewVoice(): Unit{
        var shouldIgnoreInitialVoice: Boolean = this._state.voiceIndex == 0.0 && !this._state.ignoredInitialVoice
        if (shouldIgnoreInitialVoice)
        {
            if (this._state.currentStaff!!.bars.length == 0.0)
            {
                shouldIgnoreInitialVoice = true
            }
            else 
            {
                when (this._state.voiceMode)
                {
                    com.omnifret.gplayer.importer.gplayertex.GPlayerTexVoiceMode.StaffWise -> 
                    {
                        shouldIgnoreInitialVoice = this._state.currentStaff!!.bars.length == 1.0 && this._state.currentStaff!!.bars[(0).toInt()].isEmpty
                    }
                    com.omnifret.gplayer.importer.gplayertex.GPlayerTexVoiceMode.BarWise -> 
                    {
                        if (this._state.barIndex < this._state.currentStaff!!.bars.length)
                        {
                            var bar: com.omnifret.gplayer.model.Bar = this._state.currentStaff!!.bars[(this._state.barIndex).toInt()]
                            shouldIgnoreInitialVoice = bar.voices[(0).toInt()].isEmpty
                        }
                        else 
                        {
                            shouldIgnoreInitialVoice = true
                        }
                    }
                    else -> { }
                }
            }
        }
        if (shouldIgnoreInitialVoice)
        {
            this._state.ignoredInitialVoice = true
            return
        }
        when (this._state.voiceMode)
        {
            com.omnifret.gplayer.importer.gplayertex.GPlayerTexVoiceMode.StaffWise -> 
            {
                this._state.voiceIndex++
                this._state.barIndex = 0.0
                this._state.currentTupletDenominator = -1.0
                this._state.currentTupletNumerator = -1.0
            }
            com.omnifret.gplayer.importer.gplayertex.GPlayerTexVoiceMode.BarWise -> 
            {
                this._state.voiceIndex++
                this._state.currentTupletDenominator = -1.0
                this._state.currentTupletNumerator = -1.0
            }
            else -> { }
        }
        for (b in this._state.currentStaff!!.bars)
        {
            while (b.voices.length <= this._state.voiceIndex)
            {
                b.addVoice(com.omnifret.gplayer.model.Voice())
            }
        }
    }
    
    public constructor()
    : super()
}

@kotlin.contracts.ExperimentalContracts
@kotlin.ExperimentalUnsignedTypes
public class GPlayerTexErrorWithDiagnostics: com.omnifret.gplayer.GPlayerError
{
    public var lexerDiagnostics: com.omnifret.gplayer.importer.gplayertex.GPlayerTexDiagnosticBag? = null
    
    public var parserDiagnostics: com.omnifret.gplayer.importer.gplayertex.GPlayerTexDiagnosticBag? = null
    
    public var semanticDiagnostics: com.omnifret.gplayer.importer.gplayertex.GPlayerTexDiagnosticBag? = null
    
    public fun iterateDiagnostics(): kotlin.collections.Iterator<com.omnifret.gplayer.importer.gplayertex.GPlayerTexDiagnostic> = iterator{
